# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_login import login_required, current_user

app = Flask(__name__)

# Mock user database
users = {
    1: {"id": 1, "username": "john_doe", "email": "john@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    2: {"id": 2, "username": "jane_smith", "email": "jane@example.com", "role": "moderator", "account_status": "active", "subscription_tier": "pro"}
}

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if not current_user.is_admin:
        return jsonify({"error": "Unauthorized"}), 403
    
    user = users.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    data = request.get_json()
    
    # Validate allowed fields
    allowed_fields = {'username', 'email', 'role', 'account_status', 'subscription_tier'}
    invalid_fields = set(data.keys()) - allowed_fields
    if invalid_fields:
        return jsonify({"error": f"Invalid fields: {', '.join(invalid_fields)}"}), 400
    
    # Validate role
    if 'role' in data and data['role'] not in ['user', 'moderator', 'admin']:
        return jsonify({"error": "Invalid role"}), 400
    
    # Validate account_status
    if 'account_status' in data and data['account_status'] not in ['active', 'suspended']:
        return jsonify({"error": "Invalid account_status"}), 400
    
    # Validate subscription_tier
    if 'subscription_tier' in data and data['subscription_tier'] not in ['free', 'pro', 'enterprise']:
        return jsonify({"error": "Invalid subscription_tier"}), 400
    
    # Update user
    for key, value in data.items():
        user[key] = value
    
    return jsonify(user), 200